import { useState } from "react";
import {
  Box,
  TextField,
  Button,
  Typography,
  Card,
  CardContent,
  IconButton,
  InputAdornment,
  Dialog,
  DialogTitle,
  DialogContent,
} from "@mui/material";
import { Visibility, VisibilityOff, ContentCopy } from "@mui/icons-material";
import API from "../../api/axios";
import Topbar from "../../layouts/Topbar";
import Sidebar from "../../layouts/Sidebar"; // 🔥 ADD SIDEBAR

export default function CreateOrganization() {
  const [form, setForm] = useState({
    organization: "", // 🔥 FIXED NAME
    username: "",
    password: "",
    confirmPassword: "",
  });

  const [showPassword, setShowPassword] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);

  const copyCredentials = () => {
    navigator.clipboard.writeText(
      `Username: ${form.username}\nPassword: ${form.password}`,
    );
    alert("Copied ✅");
  };

  const createOrg = async () => {
    if (!form.organization || !form.username || !form.password) {
      alert("All fields are required ❌");
      return;
    }

    if (form.password !== form.confirmPassword) {
      alert("Passwords do not match ❌");
      return;
    }

    try {
      await API.post("create-admin/", {
        organization: form.organization, // 🔥 FIXED
        username: form.username,
        password: form.password,
      });

      setOpenDialog(true);
    } catch (err) {
      console.log(err);
      alert("Error ❌");
    }
  };

  return (
    <>
      <Topbar />
      <Sidebar /> {/* 🔥 SIDEBAR */}
      <Box
        sx={{
          display: "flex",
        }}
      >
        {/* 🔥 MAIN CONTENT */}
        <Box
          sx={{
            flex: 1,
            ml: { md: "240px" }, // sidebar width
            mt: 10,
            p: 3,
            minHeight: "100vh",
            background: "#f5f7fa",
          }}
        >
          <Typography variant="h5" mb={3}>
            🏢 Create Organization
          </Typography>

          <Card sx={{ maxWidth: 500 }}>
            <CardContent>
              {/* Organization */}
              <TextField
                fullWidth
                label="Organization Name"
                margin="normal"
                onChange={(e) =>
                  setForm({ ...form, organization: e.target.value })
                }
              />

              {/* Username */}
              <TextField
                fullWidth
                label="Admin Username"
                margin="normal"
                onChange={(e) => setForm({ ...form, username: e.target.value })}
              />

              {/* Password */}
              <TextField
                fullWidth
                label="Password"
                type={showPassword ? "text" : "password"}
                margin="normal"
                value={form.password}
                onChange={(e) => setForm({ ...form, password: e.target.value })}
                InputProps={{
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={() => setShowPassword(!showPassword)}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              {/* Confirm Password */}
              <TextField
                fullWidth
                label="Confirm Password"
                type="password"
                margin="normal"
                value={form.confirmPassword}
                onChange={(e) =>
                  setForm({ ...form, confirmPassword: e.target.value })
                }
              />

              {/* Button */}
              <Button
                fullWidth
                variant="contained"
                sx={{ mt: 2 }}
                onClick={createOrg}
              >
                Create Organization
              </Button>
            </CardContent>
          </Card>
        </Box>
      </Box>
      {/* ✅ Success Dialog */}
      <Dialog open={openDialog} onClose={() => setOpenDialog(false)}>
        <DialogTitle>🎉 Organization Created!</DialogTitle>
        <DialogContent>
          <Typography>
            <b>Organization:</b> {form.organization}
          </Typography>
          <Typography>
            <b>Username:</b> {form.username}
          </Typography>
          <Typography>
            <b>Password:</b> {form.password}
          </Typography>

          <Button
            startIcon={<ContentCopy />}
            onClick={copyCredentials}
            sx={{ mt: 2 }}
          >
            Copy Credentials
          </Button>
        </DialogContent>
      </Dialog>
    </>
  );
}
